import{_ as e,o as t,c as i,a3 as o}from"./chunks/framework.CjquFG0V.js";const m=JSON.parse('{"title":"100. Incident Reporting Investigation And Prevention","description":"","frontmatter":{"title":"100. Incident Reporting Investigation And Prevention","eba":"Nurses and Midwives 2024-2028","topics":["preliminary"]},"headers":[],"relativePath":"ebas/nurses-midwives/ohs/100-incident-reporting-investigation-and-prevention.md","filePath":"ebas/nurses-midwives/ohs/100-incident-reporting-investigation-and-prevention.md"}'),r={name:"ebas/nurses-midwives/ohs/100-incident-reporting-investigation-and-prevention.md"};function a(s,n,p,d,g,c){return t(),i("div",null,[...n[0]||(n[0]=[o('<h1 id="_100-incident-reporting-investigation-and-prevention" tabindex="-1">100. Incident Reporting Investigation And Prevention <a class="header-anchor" href="#_100-incident-reporting-investigation-and-prevention" aria-label="Permalink to &quot;100. Incident Reporting Investigation And Prevention&quot;">​</a></h1><p><strong>100.1</strong> The Employer will facilitate timely reporting of incidents by Employees and ensure Employees who report incidents are appropriately supported.</p><p><strong>100.2</strong> Following an incident, the Employer will as soon as practicable:</p><p><strong>(a)</strong> provide the Employee(s) with access to post incident support services;</p><p><strong>(b)</strong> take appropriate action to prevent further injury to Employee(s);</p><p><strong>(c)</strong> conduct an incident investigation in a timely manner and implement workplace controls to prevent the incident recurring; and</p><p><strong>(d)</strong> provide information regarding the Employee&#39;s rights as relevant including the making and lodging of a workers compensation claim or reporting to police.</p><p><strong>100.3</strong> The Employer will provide information, instruction and training to Employees and management staff regarding the importance of timely reporting, procedures regarding incident reporting, and linking this to incident investigation and prevention.</p><p>Plain language terms: incident report, near miss.</p>',9)])])}const v=e(r,[["render",a]]);export{m as __pageData,v as default};
